const body = $input.first().json.body || $input.first().json;
const requiredFields = ['clientName', 'clientEmail', 'typeId', 'description', 'canal', 'agenceId'];
const missing = requiredFields.filter(f => !body[f]);
if (missing.length > 0) throw new Error(`Champs manquants: ${missing.join(', ')}`);
const slaMap = { 1: { slaHeures: 24, priorite: 'High' }, 'default': { slaHeures: 72, priorite: 'Low' } };
const slaInfo = slaMap[body.typeId] || slaMap['default'];
const maintenant = new Date();
return [{ json: { clientName: body.clientName, clientEmail: body.clientEmail, typeId: body.typeId, description: body.description, canal: body.canal, agenceId: body.agenceId, priorite: body.priorite || slaInfo.priorite, slaHeures: slaInfo.slaHeures, slaDueDate: new Date(maintenant.getTime() + slaInfo.slaHeures * 3600000).toISOString(), dateCreation: maintenant.toISOString(), statut: 'Pending', refReclamation: `REF-${Date.now()}` } }];

// Algorithme d'attribution intelligente
// Prend l'agent avec la plus faible charge
// Si plusieurs agents ont la même charge, prend celui avec la spécialité correspondante

const agents = $input.all().map(i => i.json);
const typeReclamation = $('Valider & Enrichir Données').item.json.type;
const complaintId = $('Insérer Réclamation SQL').item.json.Id;
const enriched = $('Valider & Enrichir Données').item.json;

if (!agents || agents.length === 0) {
  throw new Error('Aucun agent disponible dans cette agence');
}

// Trier: priorité à la spécialité correspondante, puis par charge
const agentTrie = agents.sort((a, b) => {
  const aSpec = (a.Specialite || '').includes(typeReclamation) ? -1 : 0;
  const bSpec = (b.Specialite || '').includes(typeReclamation) ? -1 : 0;
  if (aSpec !== bSpec) return aSpec - bSpec;
  return (a.chargeActuelle || 0) - (b.chargeActuelle || 0);
});

const agentChoisi = agentTrie[0];

const maintenant = new Date().toISOString();

return [{
  json: {
    complaintId: complaintId,
    agentId: agentChoisi.agentId,
    agentNom: `${agentChoisi.Prenom} ${agentChoisi.Nom}`,
    agentEmail: agentChoisi.Email,
    chargeAvant: agentChoisi.chargeActuelle,
    refReclamation: enriched.refReclamation,
    type: enriched.type,
    priorite: enriched.priorite,
    slaDueDate: enriched.slaDueDate,
    slaHeures: enriched.slaHeures,
    dateAssignation: maintenant,
    clientId: enriched.clientId,
    description: enriched.description
  }
}];

